const incoming = $input.first()?.json ?? {};
const body = incoming.body ?? incoming;
const query = (body.query ?? '한국 AI 트렌드').toString();
const collectedAt = (body.collected_at ?? new Date().toISOString()).toString();

const sourceItems = Array.isArray(body.results) ? body.results : (Array.isArray(body.items) ? body.items : []);
const normalizedItems = sourceItems
  .map((entry, index) => {
    const title = (entry?.title ?? `untitled-${index + 1}`).toString().trim();
    const url = (entry?.url ?? '').toString().trim();
    const snippet = (entry?.snippet ?? '').toString().trim();
    let bucket = (entry?.bucket ?? '').toString().trim().toUpperCase();
    if (!['HOT', 'INSIGHT', 'MONITOR'].includes(bucket)) {
      const lowered = `${title} ${snippet}`.toLowerCase();
      if (lowered.includes('launch') || lowered.includes('release') || lowered.includes('breaking') || lowered.includes('급등')) {
        bucket = 'HOT';
      } else if (lowered.includes('analysis') || lowered.includes('report') || lowered.includes('전망') || lowered.includes('인사이트')) {
        bucket = 'INSIGHT';
      } else {
        bucket = 'MONITOR';
      }
    }
    return {
      title,
      url,
      snippet,
      bucket,
    };
  })
  .slice(0, 30);

return [
  {
    json: {
      query,
      collected_at: collectedAt,
      items: normalizedItems,
    },
  },
];

const data = $input.first()?.json ?? {};
const query = data.query ?? '한국 AI 트렌드';
const collectedAt = data.collected_at ?? new Date().toISOString();
const items = Array.isArray(data.items) ? data.items : [];

const buckets = {
  HOT: [],
  INSIGHT: [],
  MONITOR: [],
};
for (const item of items) {
  const key = ['HOT', 'INSIGHT', 'MONITOR'].includes(item.bucket) ? item.bucket : 'MONITOR';
  buckets[key].push(item);
}

const toLines = (bucketItems) => {
  if (!bucketItems.length) {
    return ['- 없음'];
  }
  return bucketItems.map((item, index) => {
    const title = item.title || `Item ${index + 1}`;
    const url = item.url ? ` (${item.url})` : '';
    const snippet = item.snippet ? `\n  - 요약: ${item.snippet}` : '';
    return `- ${title}${url}${snippet}`;
  });
};

const markdown = [
  '# Hermes Daily Briefing',
  '',
  `- generated_at: ${new Date().toISOString()}`,
  `- collected_at: ${collectedAt}`,
  `- query: ${query}`,
  '',
  '## HOT',
  ...toLines(buckets.HOT),
  '',
  '## INSIGHT',
  ...toLines(buckets.INSIGHT),
  '',
  '## MONITOR',
  ...toLines(buckets.MONITOR),
  '',
  '## 액션 제안',
  '- Minerva: HOT 항목 우선순위 반영 검토',
  '- Clio: INSIGHT 항목 문서화/지식베이스 반영',
].join('\n');

const summary = {
  total: items.length,
  hot: buckets.HOT.length,
  insight: buckets.INSIGHT.length,
  monitor: buckets.MONITOR.length,
};

return [
  {
    json: {
      query,
      collected_at: collectedAt,
      generated_at: new Date().toISOString(),
      items,
      has_items: items.length > 0,
      bucket_counts: summary,
      briefing_markdown: markdown,
      summary: `total=${summary.total}, hot=${summary.hot}, insight=${summary.insight}, monitor=${summary.monitor}`,
    },
  },
];

const current = $input.first()?.json ?? {};
const staticData = $getWorkflowStaticData('global');

const makeFingerprint = (value) => {
  const str = String(value ?? '');
  let hash = 0;
  for (let i = 0; i < str.length; i += 1) {
    hash = (hash * 31 + str.charCodeAt(i)) >>> 0;
  }
  return hash.toString(16);
};

const dateKey = new Date().toISOString().slice(0, 10);
const fingerprintSource = `${current.query}\n${(current.items ?? []).map((item) => `${item.title}|${item.url}|${item.snippet}`).join('\n')}`;
const fingerprint = makeFingerprint(fingerprintSource);

const hasItems = Boolean(current.has_items);
const duplicate = hasItems && staticData.last_fingerprint === fingerprint && staticData.last_date === dateKey;

let skipped = false;
let skipReason = null;

if (!hasItems) {
  skipped = true;
  skipReason = 'no_results';
} else if (duplicate) {
  skipped = true;
  skipReason = 'duplicate_briefing';
} else {
  staticData.last_fingerprint = fingerprint;
  staticData.last_date = dateKey;
  staticData.last_generated_at = new Date().toISOString();
}

return [
  {
    json: {
      ...current,
      fingerprint,
      skipped,
      skip_reason: skipReason,
      duplicate,
    },
  },
];

const data = $input.first()?.json ?? {};

return [
  {
    json: {
      ok: true,
      source: 'n8n-local',
      workflow: 'hermes-daily-briefing',
      skipped: Boolean(data.skipped),
      reason: data.skip_reason ?? null,
      duplicate: Boolean(data.duplicate),
      fingerprint: data.fingerprint ?? null,
      summary: data.summary ?? null,
      bucket_counts: data.bucket_counts ?? { total: 0, hot: 0, insight: 0, monitor: 0 },
      briefing_markdown: data.skipped ? null : (data.briefing_markdown ?? null),
      generated_at: data.generated_at ?? new Date().toISOString(),
      collected_at: data.collected_at ?? null,
    },
  },
];
